// Module: node_add_198
// op_type=add, OC=24, packed [rhs|lhs] (lhs low 192b, rhs high 192b)
// pipeline_latency_cycles = OC + 3 = 27
// Fused scales: FUSED_SHIFT=14
//   LHS_FUSED_MULT/2^14 ~= lhs_scale/out_scale  (16930/16384 ~= 1.033325)
//   RHS_FUSED_MULT/2^14 ~= rhs_scale/out_scale  (15515/16384 ~= 0.946960)
module node_add_198 (
    input  wire                clk,
    input  wire                rst_n,
    input  wire                valid_in,
    output reg                 ready_in,
    input  wire [383:0]        data_in,
    output reg                 valid_out,
    output reg  [191:0]        data_out
);

    localparam integer OC               = 24;
    localparam integer INPUT_WIDTH      = 384;
    localparam integer OUTPUT_WIDTH     = 192;
    localparam integer CH_IDX_W         = 5;

    localparam integer FUSED_SHIFT      = 14;
    localparam integer SCALE_CONST_W    = 16;
    localparam signed [SCALE_CONST_W-1:0] LHS_FUSED_MULT = 16'sd16930;
    localparam signed [SCALE_CONST_W-1:0] RHS_FUSED_MULT = 16'sd15515;

    localparam integer PROD_W           = 8 + SCALE_CONST_W;   // 24
    localparam integer SUM_W            = PROD_W + 2;          // 26

    localparam signed [SUM_W-1:0] ONE_S       = {{(SUM_W-1){1'b0}}, 1'b1};
    localparam signed [SUM_W-1:0] FUSED_HALF  =
        {{(SUM_W-FUSED_SHIFT){1'b0}}, 1'b1, {(FUSED_SHIFT-1){1'b0}}};
    localparam signed [SUM_W-1:0] FUSED_HALF_M1 = FUSED_HALF - ONE_S;

    localparam ST_IDLE = 1'b0;
    localparam ST_RUN  = 1'b1;

    reg                       state;
    reg [INPUT_WIDTH-1:0]     input_buf;
    reg [CH_IDX_W-1:0]        ch_idx;
    reg [CH_IDX_W-1:0]        stage1_idx;
    reg [CH_IDX_W-1:0]        stage2_idx;
    reg                       stage1_valid;
    reg                       stage2_valid;

    (* use_dsp = "yes" *) reg signed [PROD_W-1:0] lhs_term;
    (* use_dsp = "yes" *) reg signed [PROD_W-1:0] rhs_term;
    reg signed [SUM_W-1:0]    sum_term;

    wire signed [7:0]         lhs_ch;
    wire signed [7:0]         rhs_ch;
    wire signed [SUM_W-1:0]   sum_pre;
    wire signed [SUM_W-1:0]   shifted;
    wire signed [7:0]         sat_out;

    assign lhs_ch  = $signed(input_buf[ch_idx*8 +: 8]);
    assign rhs_ch  = $signed(input_buf[OUTPUT_WIDTH + ch_idx*8 +: 8]);
    assign sum_pre = lhs_term + rhs_term;
    assign shifted = sum_term >>> FUSED_SHIFT;
    assign sat_out = (shifted >  127) ?  8'sd127 :
                     (shifted < -128) ? -8'sd128 :
                     shifted[7:0];

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state         <= ST_IDLE;
            ready_in      <= 1'b1;                       // [INVARIANT:READY_IN_GATING]
            valid_out     <= 1'b0;
            data_out      <= {OUTPUT_WIDTH{1'b0}};
            input_buf     <= {INPUT_WIDTH{1'b0}};
            ch_idx        <= {CH_IDX_W{1'b0}};
            stage1_idx    <= {CH_IDX_W{1'b0}};
            stage2_idx    <= {CH_IDX_W{1'b0}};
            stage1_valid  <= 1'b0;
            stage2_valid  <= 1'b0;
            lhs_term      <= {PROD_W{1'b0}};
            rhs_term      <= {PROD_W{1'b0}};
            sum_term      <= {SUM_W{1'b0}};
        end else begin
            valid_out <= 1'b0;
            case (state)
                ST_IDLE: begin
                    ready_in     <= 1'b1;                // [INVARIANT:READY_IN_GATING]
                    stage1_valid <= 1'b0;
                    stage2_valid <= 1'b0;
                    if (valid_in) begin
                        input_buf <= data_in;
                        ch_idx    <= {CH_IDX_W{1'b0}};
                        state     <= ST_RUN;
                        ready_in  <= 1'b0;               // [INVARIANT:READY_IN_GATING]
                    end
                end
                ST_RUN: begin
                    // Stage 1 — fused multiplies (one channel per cycle).
                    if (ch_idx < OC) begin
                        lhs_term     <= lhs_ch * LHS_FUSED_MULT;
                        rhs_term     <= rhs_ch * RHS_FUSED_MULT;
                        stage1_idx   <= ch_idx;
                        stage1_valid <= 1'b1;
                        ch_idx       <= ch_idx + 1'b1;
                    end else begin
                        stage1_valid <= 1'b0;
                    end

                    // Stage 2 — sum + sign-aware round bias.
                    stage2_valid <= stage1_valid;
                    stage2_idx   <= stage1_idx;
                    if (stage1_valid) begin
                        sum_term <= sum_pre +
                                    (sum_pre[SUM_W-1] ? FUSED_HALF_M1 : FUSED_HALF);
                    end

                    // Stage 3 — arithmetic shift, saturate, pack into data_out.
                    if (stage2_valid) begin
                        // [INVARIANT:ROUNDING]
                        data_out[stage2_idx*8 +: 8] <= sat_out;
                        if (stage2_idx == OC - 1) begin
                            valid_out <= 1'b1;           // [INVARIANT:VALID_OUT_LATENCY]
                            state     <= ST_IDLE;
                            ready_in  <= 1'b1;           // [INVARIANT:READY_IN_GATING]
                        end
                    end
                end
                default: state <= ST_IDLE;
            endcase
        end
    end

endmodule
